def pct30(column):
    return column.quantile(0.3)


print(dogs["weight_kg"].agg(pct30))  # 22.6

def pct40(column):
    return column.quantile(0.4)


print(dogs["weight_kg"].agg([pct30, pct40]))
# pct30    22.6
# pct40    24.0
# Name: weight_kg, dtype: float64

